// tsconfig.json üçün qeyd: {"experimentalDecorators": true}

// 1. Sadə Xüsusiyyət Dekoratoru
function readonly(target: any, propertyKey: string) {
  Object.defineProperty(target, propertyKey, { writable: false });
}
class Person {
  @readonly
  name: string = "Alice";
}
const person = new Person();
// person.name = "Bob"; // Səhv: name yalnız oxuna bilər
console.log(person.name); // Çıxış: Alice

// 2. Dekorator Fabriki
function logProperty(prefix: string) {
  return function (target: any, propertyKey: string) {
    let value = target[propertyKey];
    Object.defineProperty(target, propertyKey, {
      get: () => {
        console.log(prefix + " Getting value: " + value);
        return value;
      },
      set: (newValue) => {
        console.log(prefix + " Setting value: " + newValue);
        value = newValue;
      }
    });
  };
}
class User {
  @logProperty("INFO")
  username: string = "Alice";
}
const user = new User();
console.log(user.username); // Çıxış: INFO Getting value: Alice
user.username = "Bob"; // Çıxış: INFO Setting value: Bob
console.log(user.username); // Çıxış: INFO Getting value: Bob

// 3. Xüsusiyyət Dəyərini Validasiya Edən Dekorator
function restrictLength(maxLength: number) {
  return function (target: any, propertyKey: string) {
    let value = target[propertyKey];
    Object.defineProperty(target, propertyKey, {
      get: () => value,
      set: (newValue) => {
        if (typeof newValue === "string" && newValue.length <= maxLength) {
          value = newValue;
        } else {
          console.log("Error: Value exceeds max length " + maxLength);
        }
      }
    });
  };
}
class Profile {
  @restrictLength(10)
  bio: string = "Developer";
}
const profile = new Profile();
profile.bio = "Software Engineer"; // Çıxış: Error: Value exceeds max length 10
console.log(profile.bio); // Çıxış: Developer
profile.bio = "Coder"; // Dəyər dəyişir
console.log(profile.bio); // Çıxış: Coder

// 4. Digər Dekoratorlarla Birləşmə
function logMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log("Method " + propertyKey + " called with args: " + args);
    return originalMethod.apply(this, args);
  };
}
class Store {
  @logProperty("STORE")
  name: string = "MyStore";

  @logMethod
  updateName(newName: string): string {
    this.name = newName;
    return this.name;
  }
}
const store = new Store();
store.updateName("NewStore"); // Çıxış: Method updateName called with args: NewStore
// Çıxış: STORE Setting value: NewStore
console.log(store.name); // Çıxış: STORE Getting value: NewStore

// Mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}

function validatePrice(target: any, propertyKey: string) {
  let value = target[propertyKey];
  Object.defineProperty(target, propertyKey, {
    get: () => value,
    set: (newValue) => {
      if (typeof newValue === "number" && newValue >= 0) {
        value = newValue;
      } else {
        console.log("Error: Price must be a positive number");
      }
    }
  });
}

class Store {
  products: Product[] = [];

  @validatePrice
  totalPrice: number = 0;

  addProduct(product: Product): Product[] {
    this.products = [...this.products, product];
    this.totalPrice += product.price;
    return this.products;
  }
}

const store = new Store();
const laptop: Product = { id: "P001", name: "Laptop", price: 999 };
store.addProduct(laptop);
console.log(store.totalPrice); // Çıxış: 999
store.totalPrice = -100; // Çıxış: Error: Price must be a positive number
console.log(store.totalPrice); // Çıxış: 999
store.totalPrice = 1500; // Dəyər dəyişir
console.log(store.totalPrice); // Çıxış: 1500

